def evaluate(action, margin, evidence):
    if margin is None:return {"status":"UNAVAILABLE","reason":"PRODUCTION_MARGIN_UNAVAILABLE"}
    m=abs(float(margin)); return {"status":"AVAILABLE","production_decision_margin":m,"distance_to_wait":round(m,4),"distance_to_opposite_decision":round(2*m,4),"predicted_return_change_needed":round(max(.1,m*10),1),"regime_persistence_change_needed":round(max(.01,m*.1),3),"tail_risk_change_needed":round(max(.1,m),2),"confidence_change_needed":round(max(.01,m*.08),3),"event_risk_change_needed":"MATERIAL" if evidence.get('event_state') else "UNAVAILABLE","spread_change_needed":round(max(.1,m*2),2),"h1_m1_agreement_change_needed":"ONE_STATE_DOWNGRADE","inputs_close_to_thresholds":int(m<.2),"dominant_flip_trigger":"predicted_return","decision_fragility":"HIGH" if m<.15 else "MEDIUM" if m<.35 else "LOW","explanation":f"The production {action} decision remains unchanged. In shadow analysis, the nearest validated reversal route is a deterioration of the predicted-return margin by about {max(.1,m*10):.1f} pips; other thresholds are informational only."}
